let data = msg.payload;

// Proteção caso a mensagem ainda esteja como string
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (error) {
        node.error("Invalid JSON received", msg);
        return null;
    }
}

if (
    !data.client_id ||
    !data.seat ||
    data.ts === undefined ||
    data.weight_g === undefined ||
    data.occupied === undefined
) {
    node.warn("Incomplete seat message");
    return null;
}

const epoch = Number(data.ts);

if (!Number.isFinite(epoch) || epoch <= 0) {
    node.warn("Invalid epoch timestamp");
    return null;
}

/*
 * ESP32 envia epoch em segundos.
 * JavaScript Date e ui-chart trabalham melhor com milissegundos.
 */
const epochMs = epoch < 1000000000000
    ? epoch * 1000
    : epoch;

const date = new Date(epochMs);

if (Number.isNaN(date.getTime())) {
    node.warn("Invalid date");
    return null;
}

const brazilFormatter = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
});

data.ts_seconds = Math.floor(epochMs / 1000);
data.ts_ms = epochMs;
data.datetime_brt = brazilFormatter.format(date);

// Campos úteis para nós posteriores
msg.payload = data;
msg.timestamp = epochMs;
msg.seat = data.seat;
msg.topic = data.seat;

return msg;

const data = msg.payload;

if (
    !data ||
    !data.client_id ||
    !data.seat ||
    data.ts === undefined
) {
    node.warn("Invalid seat message");
    return null;
}

/*
 * Identificador da leitura.
 *
 * Incluímos todos os valores principais porque duas leituras
 * diferentes podem, em alguns casos, possuir o mesmo timestamp
 * em segundos.
 */
const eventKey = [
    String(data.client_id),
    String(data.seat),
    String(data.ts),
    String(data.adc_raw),
    Number(data.voltage).toFixed(3),
    Number(data.weight_g).toFixed(0),
    data.occupied ? "1" : "0"
].join("|");

let history = flow.get("seatHistory") || [];
let registeredEvents = flow.get("registeredSeatEvents") || {};

/*
 * A mensagem já foi processada.
 * Não envia nada para a tabela.
 */
if (registeredEvents[eventKey]) {
    node.warn(`Duplicate seat message ignored: ${eventKey}`);
    return null;
}

const epoch = Number(data.ts);

const epochMs = data.ts_ms !== undefined
    ? Number(data.ts_ms)
    : epoch * 1000;

const date = new Date(epochMs);

const formattedDate = data.datetime_brt ||
    new Intl.DateTimeFormat("pt-BR", {
        timeZone: "America/Sao_Paulo",
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
        second: "2-digit",
        hour12: false
    }).format(date);

const historyItem = {
    event_id: eventKey,
    client_id: String(data.client_id),
    seat: String(data.seat),
    status: data.occupied ? "OCCUPIED" : "AVAILABLE",
    adc_raw: Number(data.adc_raw),
    voltage: Number(data.voltage),
    weight_g: Math.round(Number(data.weight_g)),
    occupied: Boolean(data.occupied),
    ts: epoch,
    date_time: formattedDate
};

history.push(historyItem);
registeredEvents[eventKey] = true;

/*
 * Mais recente primeiro.
 */
history.sort((a, b) => b.ts - a.ts);

flow.set("seatHistory", history);
flow.set("registeredSeatEvents", registeredEvents);

/*
 * Envia sempre o histórico completo como array.
 * Assim, a tabela substitui seu conteúdo, em vez de acrescentar
 * novamente registros que já estavam nela.
 */
msg.payload = history;

return msg;

let data = msg.payload;

// Proteção caso a mensagem ainda esteja como string
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (error) {
        node.error("Invalid JSON received", msg);
        return null;
    }
}

if (
    !data ||
    !data.client_id ||
    data.ts === undefined ||
    data.seats === undefined
) {
    node.warn("Invalid heartbeat message");
    return null;
}

const epoch = Number(data.ts);

if (!Number.isFinite(epoch) || epoch <= 0) {
    node.warn("Invalid heartbeat timestamp");
    return null;
}

// ESP32 envia epoch em segundos.
// JavaScript Date trabalha com milissegundos.
const epochMs = epoch < 1000000000000
    ? epoch * 1000
    : epoch;

const date = new Date(epochMs);

const formattedDate = new Intl.DateTimeFormat("pt-BR", {
    timeZone: "America/Sao_Paulo",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
}).format(date);

msg.payload = {
    online: true,
    status: "ONLINE",
    client_id: data.client_id,
    seats: Number(data.seats),
    ts: epoch,
    ts_ms: epochMs,
    last_seen: formattedDate
};

flow.set("lastHeartbeat", msg.payload);

return msg;

/*
 * Recover the last known heartbeat state.
 */
let heartbeat = flow.get("heartbeatCardState") || {
    online: null,
    status: "WAITING",
    client_id: "—",
    seats: 4,
    last_seen: "Waiting for heartbeat",
    ts: null
};

const input = msg.payload;
const isSeatUpdate = msg.topic === "seat-update";

const isOfflineEvent =
    typeof input === "string" &&
    input.toUpperCase() === "OFFLINE";

/*
 * Update heartbeat data only for heartbeat events.
 * A seat update must not replace heartbeat information.
 */
if (isOfflineEvent) {
    heartbeat.online = false;
    heartbeat.status = "OFFLINE";
} else if (
    !isSeatUpdate &&
    input &&
    typeof input === "object"
) {
    heartbeat = {
        ...heartbeat,
        ...input,
        online: true,
        status: "ONLINE"
    };
}

flow.set("heartbeatCardState", heartbeat);

/*
 * Read the latest seat states from the flow context.
 */
const seatMap = flow.get("currentSeatMap") || {};

let seats = [];

if (Array.isArray(seatMap)) {
    seats = seatMap;
} else if (Array.isArray(seatMap.seats)) {
    seats = seatMap.seats;
} else {
    seats = Object.values(seatMap).filter(
        seat =>
            seat &&
            typeof seat === "object" &&
            typeof seat.occupied === "boolean"
    );
}

const occupiedSeats = seats.filter(
    seat => seat.occupied === true
);

const occupiedNames = occupiedSeats.map(
    seat =>
        seat.name ||
        seat.seat ||
        seat.id ||
        "Unknown seat"
);

/*
 * Critical condition:
 * ESP32 offline with one or more occupied seats.
 */
const criticalAlert =
    heartbeat.online === false &&
    occupiedNames.length > 0;

/*
 * Output 1: card update.
 *
 * This output is generated for:
 * - heartbeat messages;
 * - offline events;
 * - seat state updates.
 */
const cardMessage = {
    payload: {
        ...heartbeat,

        status: criticalAlert
            ? "CRITICAL"
            : heartbeat.status,

        occupied_count: occupiedNames.length,
        occupied_seats: occupiedNames,
        critical_alert: criticalAlert
    }
};

/*
 * Output 2: notification.
 * Avoid repeated notifications while the same alert is active.
 */
const alertWasActive =
    flow.get("heartbeatSafetyAlertActive") === true;

let notificationMessage = null;

if (criticalAlert && !alertWasActive) {
    const formattedSeats = occupiedNames
        .map(formatSeat)
        .join(", ");


    notificationMessage = {
        payload: `
            <div class="safety-notification-content">
                <div class="safety-notification-header">
                    <div class="safety-notification-icon">!</div>

                    <div>
                        <div class="safety-notification-title"> 
                            VEHICLE SAFETY ALERT
                        </div>
                        <div class="safety-notification-message">
                            The ESP32 is offline and ${occupiedNames.length} seat(s) were last reported as occupied.
                        </div>
                    </div>
                </div>

                <div class="safety-notification-seats">
                    ${occupiedNames
                    .map(seat => `<span>${formatSeat(seat)}</span>`)
                    .join("")}
                </div>

                <div class="safety-notification-instruction">
                    Check the vehicle immediately.
                </div>
            </div >
        `,

        show: true,

        ui_update: {
            raw: true,
            color: "rgb(198, 40, 40)",
            position: "top right",
            displayTime: 0,
            allowDismiss: true,
            dismissText: "Dismiss",
            showCountdown: false
        }
    };

}

/*
 * Close the notification when the critical condition clears.
 */
if (!criticalAlert && alertWasActive) {
    notificationMessage = {
        show: false
    };
}

flow.set(
    "heartbeatSafetyAlertActive",
    criticalAlert
);

return [
    cardMessage,
    notificationMessage
];

function formatSeat(value) {
    const seat = String(value || "");
    const match = seat.match(/seat-(\d+)/i);

    if (match) {
        return `Seat ${Number(match[1])}`;
    }

    return seat;
}

if (!Array.isArray(msg.payload)) {
    node.warn("History payload must be an array");
    return null;
}

msg.payload = msg.payload.map(item => ({
    client_id: item.client_id,
    seat: item.seat,
    status: item.status,
    adc_raw: Number(item.adc_raw),
    voltage: Number(Number(item.voltage).toFixed(2)),
    weight_g: Math.round(Number(item.weight_g)),
    occupied: Boolean(item.occupied),
    ts: Number(item.ts),
    date_time: item.date_time
}));

return msg;

const SEAT_IDS = [
    "seat-01",
    "seat-02",
    "seat-03",
    "seat-04"
];

const data = msg.payload;

if (!data || typeof data !== "object" || !data.seat) {
    node.warn("Invalid seat message");
    return null;
}

if (!SEAT_IDS.includes(data.seat)) {
    node.warn(`Unknown seat: ${data.seat}`);
    return null;
}

let currentSeats = flow.get("currentSeatMap") || {};

/*
 * Inicializa os quatro assentos para que todos apareçam
 * antes mesmo da primeira mensagem de cada sensor.
 */
for (const seatId of SEAT_IDS) {
    if (!currentSeats[seatId]) {
        currentSeats[seatId] = {
            client_id: null,
            seat: seatId,
            received: false,
            adc_raw: 0,
            voltage: 0,
            weight_g: 0,
            occupied: false,
            ts: null,
            ts_seconds: null,
            ts_ms: null,
            datetime_brt: "Waiting for data"
        };
    }
}

/*
 * Atualiza somente o assento informado pela mensagem.
 * Os demais mantêm o último estado recebido.
 */
currentSeats[data.seat] = {
    client_id: String(data.client_id),
    seat: String(data.seat),
    received: true,
    adc_raw: Number(data.adc_raw),
    voltage: Number(data.voltage),
    weight_g: Number(data.weight_g),
    occupied: Boolean(data.occupied),
    ts: Number(data.ts),
    ts_seconds: Number(data.ts_seconds),
    ts_ms: Number(data.ts_ms),
    datetime_brt: String(data.datetime_brt)
};

flow.set("currentSeatMap", currentSeats);

const seats = SEAT_IDS.map(seatId => {
    const seat = currentSeats[seatId];

    return {
        ...seat,
        status: !seat.received
            ? "WAITING"
            : seat.occupied
                ? "OCCUPIED"
                : "AVAILABLE"
    };
});

msg.payload = {
    client_id: data.client_id,
    seats,
    occupied: seats.filter(
        seat => seat.received && seat.occupied
    ).length,
    available: seats.filter(
        seat => seat.received && !seat.occupied
    ).length,
    waiting: seats.filter(
        seat => !seat.received
    ).length,
    total: SEAT_IDS.length
};

return msg;

