const lastHeartbeat = flow.get("lastHeartbeat") || {
    client_id: "Unknown",
    seats: 0,
    ts: null,
    ts_ms: null,
    last_seen: "No heartbeat received"
};

// Timeout gerado pelo Trigger
if (msg.payload === "OFFLINE") {
    msg.payload = {
        ...lastHeartbeat,
        online: false,
        status: "OFFLINE"
    };

    return msg;
}

// Heartbeat normal
if (
    typeof msg.payload === "object" &&
    msg.payload !== null
) {
    msg.payload = {
        ...msg.payload,
        online: true,
        status: "ONLINE"
    };

    flow.set("lastHeartbeat", msg.payload);

    return msg;
}

node.warn(`Unexpected payload: ${msg.payload}`);
return null;

