const REFRESH_TOPIC = "route-refresh";

let currentRoute = flow.get("currentRoute") || null;
const isRefresh = msg.topic === REFRESH_TOPIC;

/*
 * Mensagens MQTT atualizam a rota atual.
 * route-refresh apenas recupera o último estado armazenado.
 */
if (!isRefresh) {
  const data = msg.payload;

  if (
    !data ||
    typeof data !== "object" ||
    Array.isArray(data) ||
    !data.name ||
    data.stops === undefined ||
    data.seats_occupied === undefined ||
    data.ts === undefined ||
    !data.state ||
    data.block_alert === undefined
  ) {
    node.warn("Invalid route message");
    return [null, null];
  }

  const stops = Number(data.stops);
  const occupiedSeats = Number(data.seats_occupied);
  const timestamp = Number(data.ts);

  if (
    !Number.isFinite(stops) ||
    !Number.isFinite(occupiedSeats) ||
    !Number.isFinite(timestamp)
  ) {
    node.warn("Invalid numeric values in route message");
    return [null, null];
  }

  const blockAlert =
    data.block_alert === true ||
    String(data.block_alert).toLowerCase() === "true";

  /*
   * Aceita timestamps em segundos ou milissegundos.
   */
  const timestampMs =
    timestamp < 1000000000000
      ? timestamp * 1000
      : timestamp;

  const datetime = new Intl.DateTimeFormat(
    "pt-BR",
    {
      timeZone: "America/Sao_Paulo",
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      second: "2-digit",
      hour12: false
    }
  ).format(new Date(timestampMs));

  currentRoute = {
    name: String(data.name),
    stops,
    seats_occupied: occupiedSeats,
    state: String(data.state),
    block_alert: blockAlert,
    alert_status: blockAlert ? "ACTIVE" : "CLEAR",
    ts: timestamp,
    datetime
  };

  flow.set("currentRoute", currentRoute);
}

/* =========================================================
   SAÍDA 1 — CARD
   ========================================================= */

const cardMessage = {
  topic: "route-status",
  payload: currentRoute
    ? {
        ...currentRoute,
        waiting: false
      }
    : {
        waiting: true,
        name: "—",
        stops: 0,
        seats_occupied: 0,
        state: "Waiting",
        block_alert: false,
        alert_status: "WAITING",
        ts: null,
        datetime: "Waiting for route data"
      }
};

/* =========================================================
   SAÍDA 2 — NOTIFICAÇÃO
   ========================================================= */

const alertActive =
  currentRoute !== null &&
  currentRoute.block_alert === true;

const alertWasActive =
  flow.get("routeBlockAlertActive") === true;

let notificationMessage = null;

/*
 * Abre a notificação somente quando o alerta
 * muda de inativo para ativo.
 */
if (alertActive && !alertWasActive) {
  const routeName = escapeHtml(currentRoute.name);
  const routeState = escapeHtml(currentRoute.state);

  notificationMessage = {
    topic: "route-safety-alert",

    payload: `
      <div class="safety-notification-content">
        <div class="safety-notification-header">
          <div class="safety-notification-icon">!</div>

          <div>
            <div class="safety-notification-title">
              ROUTE SAFETY ALERT
            </div>

            <div class="safety-notification-message">
              The route "${routeName}" is blocked because
              ${currentRoute.seats_occupied} seat(s) are still
              reported as occupied.
            </div>
          </div>
        </div>

        <div class="safety-notification-seats">
          <span>
            ${currentRoute.seats_occupied} occupied seat(s)
          </span>

          <span>
            ${routeState}
          </span>
        </div>

        <div class="safety-notification-instruction">
          Verify all passengers before completing the route.
        </div>
      </div>
    `,

    show: true,

    ui_update: {
      raw: true,
      color: "rgb(198, 40, 40)",
      position: "top right",
      displayTime: 0,
      allowDismiss: true,
      dismissText: "Dismiss",
      showCountdown: false
    }
  };
}

/*
 * Fecha a notificação quando block_alert volta para false.
 */
if (!alertActive && alertWasActive) {
  notificationMessage = {
    topic: "route-safety-alert",
    show: false
  };
}

flow.set("routeBlockAlertActive", alertActive);

return [
  cardMessage,
  notificationMessage
];

function escapeHtml(value) {
  const characters = {
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#039;"
  };

  return String(value).replace(
    /[&<>"']/g,
    character => characters[character]
  );
}

const MAX_HISTORY = 200;
const data = msg.payload;

if (
  !data ||
  typeof data !== "object" ||
  !data.name ||
  data.stops === undefined ||
  data.seats_occupied === undefined ||
  data.ts === undefined ||
  !data.state ||
  data.block_alert === undefined
) {
  node.warn("Invalid route message");
  return null;
}

const routeName = String(data.name);
const stops = Number(data.stops);
const occupiedSeats = Number(data.seats_occupied);
const timestamp = Number(data.ts);
const routeState = String(data.state);

const blockAlert =
  data.block_alert === true ||
  String(data.block_alert).toLowerCase() === "true";

if (
  !Number.isFinite(stops) ||
  !Number.isFinite(occupiedSeats) ||
  !Number.isFinite(timestamp)
) {
  node.warn("Invalid numeric values in route message");
  return null;
}

/*
 * Identificador único do evento.
 *
 * Mantém o timestamp porque duas mensagens diferentes da rota
 * representam eventos diferentes no histórico.
 */
const eventKey = [
  routeName,
  String(timestamp),
  routeState,
  String(stops),
  String(occupiedSeats),
  blockAlert ? "1" : "0"
].join("|");

let history = flow.get("routeHistory") || [];
let registeredEvents =
  flow.get("registeredRouteEvents") || {};

if (!Array.isArray(history)) {
  history = [];
}

if (
  !registeredEvents ||
  typeof registeredEvents !== "object" ||
  Array.isArray(registeredEvents)
) {
  registeredEvents = {};
}

/*
 * Também verifica o próprio histórico para oferecer
 * compatibilidade com registros armazenados anteriormente.
 */
const alreadyInHistory = history.some(item =>
  item.event_id === eventKey
);

if (registeredEvents[eventKey] || alreadyInHistory) {
  node.warn(`Duplicate route message ignored: ${eventKey}`);
  return null;
}

/*
 * O timestamp da rota já está em milissegundos.
 * A verificação também suporta timestamps em segundos.
 */
const epochMs =
  timestamp < 1000000000000
    ? timestamp * 1000
    : timestamp;

const formattedDate = new Intl.DateTimeFormat(
  "pt-BR",
  {
    timeZone: "America/Sao_Paulo",
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }
).format(new Date(epochMs));

const historyItem = {
  event_id: eventKey,
  name: routeName,
  state: routeState,
  stops,
  seats_occupied: occupiedSeats,
  block_alert: blockAlert,
  alert_status: blockAlert ? "ACTIVE" : "CLEAR",
  ts: timestamp,
  datetime: formattedDate
};

history.push(historyItem);
registeredEvents[eventKey] = true;

/*
 * Registros mais recentes primeiro.
 */
history.sort((first, second) =>
  Number(second.ts) - Number(first.ts)
);

history = history.slice(0, MAX_HISTORY);

flow.set("routeHistory", history);
flow.set(
  "registeredRouteEvents",
  registeredEvents
);

/*
 * Envia sempre o histórico completo.
 */
msg.topic = "route-history";
msg.payload = history;

return msg;

if (!Array.isArray(msg.payload)) {
  node.warn("Route history payload must be an array");
  return null;
}

msg.payload = msg.payload.map(item => ({
  name: String(item.name),
  state: String(item.state),
  stops: Number(item.stops),
  seats_occupied: Number(item.seats_occupied),
  alert_status: String(item.alert_status),
  datetime: String(item.datetime),
  ts: Number(item.ts)
}));

return msg;
